"""ic_roster_health.py -- daily roster health checker."""
from datetime import date, timedelta
import yaml


def check_roster_health(path: str = "ic-roster.yaml") -> dict:
    """Return a health report for the IC roster."""
    with open(path) as f:
        roster = yaml.safe_load(f)["roster"]

    today = date.today()
    issues = []
    primary_ics = []
    expiring_soon = []

    for member in roster["members"]:
        cert_date = member["cert_date"]
        if isinstance(cert_date, str):
            from datetime import datetime
            cert_date = datetime.strptime(cert_date, "%Y-%m-%d").date()

        recert_months = roster["certification"]["recertification_months"]
        expiry = date(
            cert_date.year + (cert_date.month + recert_months - 1) // 12,
            (cert_date.month + recert_months - 1) % 12 + 1,
            cert_date.day,
        )

        days_to_expiry = (expiry - today).days

        if days_to_expiry < 0:
            issues.append(
                f"EXPIRED: {member['name']} cert expired {abs(days_to_expiry)} days ago"
            )
        elif days_to_expiry < 30:
            expiring_soon.append(
                f"EXPIRING: {member['name']} cert expires in {days_to_expiry} days"
            )

        if member["availability"] == "primary":
            primary_ics.append(member["name"])

    min_required = roster.get("minimum_certified_ics", 4)
    active_count = len([m for m in roster["members"] if m["availability"] in ("primary", "backup")])

    if active_count < min_required:
        issues.append(
            f"UNDERSTAFFED: Only {active_count} certified ICs (minimum: {min_required})"
        )

    return {
        "healthy": len(issues) == 0,
        "primary_ic_count": len(primary_ics),
        "total_certified": active_count,
        "issues": issues,
        "warnings": expiring_soon,
    }


if __name__ == "__main__":
    report = check_roster_health()
    if report["healthy"]:
        print(f"Roster healthy: {report['total_certified']} ICs certified")
    else:
        print("ROSTER ISSUES DETECTED:")
        for issue in report["issues"]:
            print(f"  - {issue}")
    for warning in report["warnings"]:
        print(f"  WARNING: {warning}")
